import t from"dgram";import p from"node:dgram";describe("dgram module",()=>{it("node:dgram should be the same as dgram",()=>{expect(p).toStrictEqual(t)}),it("should export createSocket function",()=>{expect(typeof t.createSocket).toBe("function")}),it("should export Socket class",()=>{expect(typeof t.Socket).toBe("function")}),it("should create a UDP4 socket",()=>{let e=t.createSocket("udp4");expect(e).toBeDefined()}),it("should create a UDP6 socket",()=>{let e=t.createSocket("udp6");expect(e).toBeDefined()}),it("should create a socket with options object",()=>{let e=t.createSocket({type:"udp4"});expect(e).toBeDefined()}),it("should bind and close a socket",async()=>{let e=t.createSocket("udp4");await new Promise(s=>{e.bind(()=>{s()})});let o=e.address();expect(o).toBeDefined(),expect(o.port).toBeGreaterThan(0),expect(o.family).toBe("IPv4"),await new Promise(s=>{e.close(()=>{s()})})}),it("should send and receive messages",async()=>{let e=t.createSocket("udp4"),o=t.createSocket("udp4"),s="Hello, UDP!";await new Promise((n,d)=>{let i=!1;e.on("message",(a,c)=>{try{expect(a.toString()).toBe(s),expect(c.address).toBeDefined(),expect(c.port).toBeGreaterThan(0),expect(c.family).toBe("IPv4"),i=!0}catch(r){d(r)}}),e.on("listening",()=>{let a=e.address();o.send(s,a.port,"127.0.0.1",c=>{c&&d(c)}),setTimeout(()=>{try{expect(i).toBe(!0),o.close(),e.close(),n()}catch(c){d(c)}},100)}),e.on("error",a=>{d(a)}),e.bind(0)})},5e3),it("should emit listening event",async()=>{let e=t.createSocket("udp4");await new Promise(o=>{e.on("listening",()=>{let s=e.address();expect(s).toBeDefined(),e.close(),o()}),e.bind(0)})}),it("should emit close event",async()=>{let e=t.createSocket("udp4");await new Promise(o=>{e.on("close",()=>{o()}),e.bind(()=>{e.close()})})})});
